'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import clsx from 'clsx';
import Image from 'next/image';
import { LayoutDashboard, ClipboardList, PlusSquare, LogOut } from 'lucide-react';

const navItems = [
  { label: 'Dashboard', href: '/dashboard', icon: <LayoutDashboard size={18} /> },
  { label: 'Manage Tasks', href: '/tasks', icon: <ClipboardList size={18} /> },
  { label: 'Create Task', href: '/tasks/create', icon: <PlusSquare size={18} /> },
  { label: 'Logout', href: '/logout', icon: <LogOut size={18} /> },
];

export default function Sidebar() {
  const pathname = usePathname();

  return (
    <aside className="fixed bottom-0 lg:top-16 lg:left-0 lg:h-screen w-64 bg-white p-6 shadow-md hidden md:flex flex-col ">
      {/* Profile */}
      <div className="text-center mb-10">
        <Image
          src="/avatar.jpg" // Replace with your own avatar image in /public
          alt="User Avatar"
          width={80}
          height={80}
          className="rounded-full mx-auto"
        />
        <span className="text-xs bg-blue-100 text-blue-600 px-2 py-1 rounded-full inline-block mt-2">
          Admin
        </span>
        <p className="mt-2 font-semibold">Mike</p>
        <p className="text-sm text-gray-500">mike@timetoprogram.com</p>
      </div>

      {/* Navigation */}
      <nav className=" flex-1">
        {navItems.map((item) => {
          const isActive = pathname === item.href || pathname.startsWith(item.href);

          return (
            <Link key={item.href} href={item.href}>
              <div
                className={clsx(
                  'flex items-center gap-3 px-4 py-2 rounded-md transition cursor-pointer',
                  isActive
                    ? 'bg-blue-100 text-blue-700 font-medium border-r-4 border-blue-600'
                    : 'text-gray-700 hover:bg-gray-100'
                )}
              >
                {item.icon}
                <span>{item.label}</span>
              </div>
            </Link>
          );
        })}
      </nav>
    </aside>
  );
}
